import { Component } from '@angular/core';
import { Router, NavigationStart, NavigationEnd } from '@angular/router';
import { LoadingService } from './components/shared/loading.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  title = 'Omar Chegniou | Full Stack Developer';
    loading$ = this.loadingService.loading;

  constructor(private loadingService: LoadingService,  private router: Router,) { this.router.events.subscribe(event => {

    if (event instanceof NavigationStart) {
      this.loadingService.show();
    }

    if (event instanceof NavigationEnd) {
      this.loadingService.hide();
    }

  });}
}
